    // of whether higher-priority specials also exist). This is a contract
    // between player and house: player declares what they want, server
    // checks if the hand supports it. Using detectSpecial here would
    // wrongly pick the highest-ranked special and DQ a player who chose
    // a valid-but-lower one.
    const h1 = raw.slice(0,3), h2 = raw.slice(3,8), h3 = raw.slice(8,13);
    const canForm = Logic.canFormSpecial(raw, specialName);

    if (!canForm) {
        // Wrong declaration — DQ the player
        player.disqualified     = true;
        player.disqualifyReason = `Declared ${specialName} but hand does not contain one.`;
        player.lastSpecial      = '❌ Wrong special — DQ (owes 2× bet)';
